import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.Dn0B0GT3.js";const u=JSON.parse('{"title":"Architecture Review — NanoTermV2 WebGL/WebGPU Rendering Backend","description":"","frontmatter":{},"headers":[],"relativePath":"deep_think_prompt.md","filePath":"deep_think_prompt.md"}'),n={name:"deep_think_prompt.md"};function o(l,e,s,c,d,h){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="architecture-review-—-nanotermv2-webgl-webgpu-rendering-backend" tabindex="-1">Architecture Review — NanoTermV2 WebGL/WebGPU Rendering Backend <a class="header-anchor" href="#architecture-review-—-nanotermv2-webgl-webgpu-rendering-backend" aria-label="Permalink to &quot;Architecture Review — NanoTermV2 WebGL/WebGPU Rendering Backend&quot;">​</a></h1><h2 id="project-context" tabindex="-1">Project Context <a class="header-anchor" href="#project-context" aria-label="Permalink to &quot;Project Context&quot;">​</a></h2><p><strong>ShellPort</strong> is a zero-dependency, browser-based terminal emulator library called <strong>NanoTermV2</strong>. It renders a full VT100/VT220/xterm-compatible terminal into an HTML <code>&lt;canvas&gt;</code> element using the Canvas2D API. The library is designed to be embedded in web applications to provide SSH/PTY access over WebSocket.</p><h3 id="current-architecture" tabindex="-1">Current Architecture <a class="header-anchor" href="#current-architecture" aria-label="Permalink to &quot;Current Architecture&quot;">​</a></h3><p>The entire renderer lives in <code>nanoterm.js</code> (~1800 lines). Key architectural elements:</p><ul><li><strong>Buffer Model</strong>: Per-cell objects <code>{ char, fg, bg, flags }</code> stored in <code>Array&lt;Array&lt;Cell&gt;&gt;</code> — one array per row, one object per column. Primary and alternate screen buffers with scrollback.</li><li><strong>Rendering Pipeline</strong>: Two-pass Canvas2D rendering triggered via <code>requestAnimationFrame</code>: <ul><li>Pass 1 (<code>renderRowBg</code>): Draws all background rectangles with run-length batching (coalesces consecutive cells with the same background color into single <code>fillRect</code> calls).</li><li>Pass 2 (<code>renderRowText</code>): Draws all text and decorations, also with attribute-run batching. Uses <code>fillText</code> for each character individually at precise cell coordinates to prevent subpixel drift.</li></ul></li><li><strong>Programmatic Unicode Rendering</strong>: Block elements (U+2580–U+259F), box-drawing characters (U+2500–U+257F), and braille patterns (U+2800–U+28FF) are rendered programmatically using <code>fillRect</code> rather than font glyphs. This uses a detailed segment table for box-drawing with support for light, heavy, and double line weights.</li><li><strong>Glyph Probing</strong>: A pixel-comparison system that renders characters to a hidden canvas and compares against a known &quot;tofu&quot; signature (U+FFFF) to detect missing glyphs. Results are cached per codepoint. Private Use Area availability is batch-detected.</li><li><strong>DPR Handling</strong>: High-DPI support via <code>window.devicePixelRatio</code>, scaling the canvas backing store and using <code>setTransform</code> for logical-to-physical coordinate mapping.</li><li><strong>Font Management</strong>: Fractional <code>charWidth</code> for subpixel text placement, font caching via <code>lastFont</code> string comparison.</li></ul><h3 id="known-rendering-challenges-from-recent-audits" tabindex="-1">Known Rendering Challenges (from recent audits) <a class="header-anchor" href="#known-rendering-challenges-from-recent-audits" aria-label="Permalink to &quot;Known Rendering Challenges (from recent audits)&quot;">​</a></h3><ol><li><strong>Subpixel seams</strong>: Block characters need <code>+0.5px</code> overdraw to prevent visible gaps between adjacent cells</li><li><strong>Rounded corners</strong>: Box-drawing characters at U+256D–U+2570 fall back to font rendering (curves can&#39;t be expressed as horizontal/vertical segments)</li><li><strong>SGR inversion</strong>: Correct inverse color mapping for default fg/bg sentinel values (256/257)</li><li><strong>Per-character fillText</strong>: Each glyph is drawn individually — no text run batching possible due to proportional-width prevention</li><li><strong>Full redraw on every frame</strong>: No dirty-region tracking; the entire visible buffer is re-rendered every <code>requestAnimationFrame</code></li></ol><h2 id="review-scope" tabindex="-1">Review Scope <a class="header-anchor" href="#review-scope" aria-label="Permalink to &quot;Review Scope&quot;">​</a></h2><p><strong>The Canvas2D renderer already works very well.</strong> It produces correct, visually faithful output for the full VT100/VT220/xterm feature set including programmatic Unicode rendering. This is not a &quot;fix what&#39;s broken&quot; exercise.</p><p>Our ambition is to make NanoTermV2 <strong>the most performant, yet lightweight, web terminal ever built</strong> — maintaining the <strong>zero-dependency philosophy</strong> while pushing rendering to the hardware limit. We want to introduce a <strong>WebGL2</strong> (and optionally <strong>WebGPU</strong>) rendering backend that <strong>coexists</strong> with the proven Canvas2D fallback. The GPU path should achieve:</p><ul><li><strong>Pixel-perfect rendering</strong>: Zero visual compromises — the GPU renderer must match or exceed Canvas2D fidelity for every glyph, decoration, and special character</li><li><strong>Maximum throughput</strong>: Handle <code>cat /dev/urandom | xxd</code> or scrolling 100K-line files at the GPU&#39;s vsync rate, not the CPU&#39;s text-shaping rate</li><li><strong>Minimal weight</strong>: No WebGL helper libraries, no third-party glyph rasterizers — the GPU renderer should be as self-contained as the Canvas2D renderer (~2000 lines or less)</li><li><strong>Graceful coexistence</strong>: Canvas2D remains the default fallback; GPU rendering is opt-in and degrades transparently</li></ul><h3 id="key-architectural-questions" tabindex="-1">Key Architectural Questions <a class="header-anchor" href="#key-architectural-questions" aria-label="Permalink to &quot;Key Architectural Questions&quot;">​</a></h3><ol><li><p><strong>Renderer Abstraction Layer</strong>: How should we design the interface between the terminal emulator (parser, buffer, state) and the renderer? What is the right abstraction boundary so Canvas2D, WebGL, and WebGPU renderers can be swapped at runtime or selected at initialization?</p></li><li><p><strong>Glyph Atlas Strategy</strong>: WebGL/WebGPU terminal renderers typically pre-render glyphs into a texture atlas. How should we:</p><ul><li>Build and manage the atlas (static vs dynamic/LRU)?</li><li>Handle the existing programmatic Unicode characters (block elements, box drawing, braille) — should these be atlas entries or shader-generated?</li><li>Handle glyph probing for PUA/Nerd Font symbols in the GPU context?</li><li>Deal with font changes and DPR changes (atlas invalidation)?</li></ul></li><li><p><strong>Buffer-to-GPU Data Flow</strong>: The current buffer uses per-cell JS objects. What is the optimal data structure for GPU upload?</p><ul><li>Typed arrays? Packed attribute encoding?</li><li>How to minimize per-frame data transfer between CPU and GPU?</li><li>Dirty-region tracking to enable partial buffer updates?</li></ul></li><li><p><strong>Feature Parity Concerns</strong>: Which current features are trivial/hard/impossible to replicate in a GPU renderer?</p><ul><li>Text decorations (underline, double underline, strikethrough, overline)</li><li>Selection highlighting with alpha blending</li><li>Cursor rendering with blink animation</li><li>Scrollback buffer scrolling</li><li>High-DPI / devicePixelRatio handling</li></ul></li><li><p><strong>Fallback Strategy</strong>: How should the system handle:</p><ul><li>Browsers without WebGL2/WebGPU support?</li><li>WebGL context loss (and restoration)?</li><li>Mobile devices with limited GPU memory?</li></ul></li></ol><h2 id="attached-context-packs" tabindex="-1">Attached Context Packs <a class="header-anchor" href="#attached-context-packs" aria-label="Permalink to &quot;Attached Context Packs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th><th>Token Estimate</th></tr></thead><tbody><tr><td><code>context_full.md</code></td><td>Complete shellport source: nanoterm.js, app.js, server.ts, client.ts, crypto, types, tests, config</td><td>~56K</td></tr></tbody></table><h2 id="focus-areas" tabindex="-1">Focus Areas <a class="header-anchor" href="#focus-areas" aria-label="Permalink to &quot;Focus Areas&quot;">​</a></h2><ol><li><p><strong>Renderer Interface Design</strong>: Propose a clean abstraction that separates terminal state from rendering. Consider:</p><ul><li>What methods/data the renderer needs from the terminal (buffer access, cursor state, selection, scroll offset)</li><li>What events the terminal needs from the renderer (resize measurements, glyph metrics)</li><li>Whether the terminal buffer format itself should change to be GPU-friendly from the start</li></ul></li><li><p><strong>WebGL Text Rendering Pipeline</strong>: Design the glyph atlas and text rendering approach:</p><ul><li>Atlas texture format and layout (monochrome vs RGBA, grid vs bin-packed)</li><li>Dynamic atlas growth strategy for uncommon glyphs</li><li>Subpixel positioning considerations (or lack thereof in a monospace grid)</li><li>How programmatic characters (blocks, box drawing) should be generated — atlas bake vs fragment shader</li></ul></li><li><p><strong>GPU Buffer Management</strong>: Design the CPU→GPU data transfer:</p><ul><li>Packed cell representation (codepoint + fg + bg + flags in how many bytes per cell?)</li><li>Uniform buffer vs texture-based cell data</li><li>Instanced rendering vs full-screen quad approaches</li><li>Dirty-row tracking and partial upload strategies</li></ul></li><li><p><strong>Shader Architecture</strong>: Outline the vertex/fragment shader design:</p><ul><li>Background and foreground in one pass or two?</li><li>How to handle text decorations (underline, strikethrough) — geometry vs fragment shader</li><li>Alpha blending for selection overlay</li><li>Cursor rendering approach</li></ul></li><li><p><strong>WebGPU Future-Proofing</strong>: Consider how the design supports a future WebGPU backend:</p><ul><li>Compute shader opportunities (buffer diff, glyph rasterization)</li><li>Shared abstractions between WebGL and WebGPU</li><li>Whether to target WebGPU first and polyfill down to WebGL</li></ul></li><li><p><strong>Performance Analysis</strong>: Identify the actual bottlenecks in the current Canvas2D renderer and quantify the expected improvement from GPU rendering:</p><ul><li>Where does the current renderer spend the most time? (fillRect? fillText? getImageData for glyph probing?)</li><li>What throughput improvement is realistic for terminal scrolling?</li><li>Are there intermediate optimizations (dirty tracking, offscreen canvas workers) worth doing before the GPU jump?</li></ul></li><li><p><strong>Migration Path</strong>: Propose a phased implementation plan:</p><ul><li>What can be built first as a standalone proof-of-concept?</li><li>How to integrate incrementally without breaking the existing Canvas2D renderer?</li><li>Testing strategy for visual correctness comparison between renderers</li></ul></li></ol><h2 id="output-format" tabindex="-1">Output Format <a class="header-anchor" href="#output-format" aria-label="Permalink to &quot;Output Format&quot;">​</a></h2><p>For each focus area, provide:</p><ul><li><strong>Assessment</strong>: Current state analysis and key considerations</li><li><strong>Recommendation</strong>: Concrete architectural recommendation with rationale</li><li><strong>Code Sketch</strong>: Where helpful, provide pseudocode or interface definitions</li><li><strong>Risk</strong>: What could go wrong and how to mitigate</li></ul><p>End with:</p><ul><li><strong>Priority-ordered implementation roadmap</strong> (what to build first, second, third)</li><li><strong>Critical design decisions</strong> that must be made before writing any code</li><li><strong>Overall feasibility assessment</strong> with estimated complexity per phase</li></ul>',23)])])}const p=t(n,[["render",o]]);export{u as __pageData,p as default};
